// ── Firebase storage wrappers (uid injected at call site) ──
// These are set up in App component and passed down or called directly
let _currentUid = null;
function setCurrentUid(uid) { _currentUid = uid; }
async function sg(k) { 
  if (!_currentUid) return null;
  return await fsGet(_currentUid, k); 
}
async function ss(k, v) { 
  if (!_currentUid) return;
  await fsSet(_currentUid, k, v); 
}
async function sd(k) { 
  if (!_currentUid) return;
  await fsDel(_currentUid, k); 
}
// Write a sentinel doc at users/{uid} so admin getDocs("users") can list all users
async function ssParent(uid, email, name) {
  try {
    const { getFirestore, doc, setDoc } = await import("firebase/firestore");
    const db = getFirestore();
    await setDoc(doc(db, "users", uid), { email, name, createdAt: Date.now() }, { merge: true });
  } catch(e) { console.error("ssParent error", e); }
}

// Session storage (shared, by session code)
async function sgSession(code) { return await fsGetSession(code); }
async function ssSession(code, data) { await fsSetSession(code, data); }

// Partial session update — only writes the specified fields, never overwrites coin data.
// MUST use this for heartbeat/status flags to avoid overwriting concurrent coin awards.
async function ssSessionPatch(code, fields) {
  try {
    const { getFirestore, doc, updateDoc } = await import("firebase/firestore");
    const db = getFirestore();
    await updateDoc(doc(db, "sessions", code), fields);
  } catch(e) {
    // Silently ignore — never fall back to ssSession(fields) because that would
    // overwrite the entire session document with only the heartbeat fields,
    // wiping all participants and coin data.
  }
}

// Auto-claim beta invite if one exists for this email
async function claimBetaInvite(uid, email) {
  try {
    const { getFirestore, doc, getDoc, setDoc, deleteDoc } = await import("firebase/firestore");
    const db = getFirestore();
    const key = email.toLowerCase().replace(/\./g,"_");
    const inviteSnap = await getDoc(doc(db, "betaInvites", key));
    if (!inviteSnap.exists()) return null;
    const { expiry } = inviteSnap.data();
    // Already expired before they signed up — ignore
    if (new Date(expiry) < new Date()) { await deleteDoc(doc(db, "betaInvites", key)); return null; }
    // Assign beta plan
    await Promise.all([
      setDoc(doc(db, "users", uid, "data", "plan"),       { value: "beta",   updatedAt: Date.now() }),
      setDoc(doc(db, "users", uid, "data", "planExpiry"), { value: expiry,   updatedAt: Date.now() }),
      deleteDoc(doc(db, "betaInvites", key)), // consume the invite
    ]);
    return expiry;
  } catch(e) { console.error("claimBetaInvite error", e); return null; }
}

